  'https://images.unsplash.com/photo-1540541338287-41700207dee6?w=1600&q=80',
  'A private island sanctuary in the Maldives where barefoot luxury meets extraordinary celebration.',
  'Noonu Atoll, Maldives',
  'island_resort',
  'dark',
  '[{"id": "51899540-3611-4c53-84a3-2f715b10a134", "type": "hero", "content": {"title": "Soneva Jani", "tagline": "A private island sanctuary where nature meets barefoot luxury", "image": "https://images.unsplash.com/photo-1540541338287-41700207dee6?w=1600&q=80", "overlay_opacity": 0.45}, "layout": {}}, {"id": "1173a737-b9b5-44fc-8edf-17f15213c29f", "type": "stats", "content": {"eyebrow": "The Numbers", "items": [{"value": "40", "label": "Private Villas", "sublabel": "overwater & beachfront"}, {"value": "100", "label": "Max Guests", "sublabel": "for celebrations"}, {"value": "100%", "label": "Private Island", "sublabel": "exclusively yours"}, {"value": "5 km", "label": "From Mainland", "sublabel": ""}]}, "layout": {"variant": "strip", "accentBg": "#1a1209"}}, {"id": "6cec539a-cbf8-40f5-ac95-45c517855ea8", "type": "intro", "content": {"eyebrow": "The Island", "headline": "A Complete Private Retreat", "body": "Set within a UNESCO Biosphere Reserve in the Maldives, this overwater sanctuary invites couples to celebrate surrounded by nothing but ocean, sky, and the rustle of palm fronds. Arrival is by seaplane \u2014 the moment the turquoise lagoon comes into view, the world below is already a memory."}, "layout": {"variant": "centered", "accentBg": "#0f0e0c"}}, {"id": "b106ddad-474d-4b06-81c5-e4c4620d94f3", "type": "feature", "content": {"eyebrow": "The Villas", "headline": "Overwater Seclusion", "body": "Each villa sits on stilts above a private lagoon, with a retractable roof that opens to the night sky. Guests wake to the sound of water and fall asleep beneath the stars. The largest water retreats sleep entire wedding parties in one connected compound.", "image": "https://images.unsplash.com/photo-1439066615861-d1af74d74000?w=1200&q=80"}, "layout": {"variant": "image-left", "accentBg": "#0f0e0c"}}, {"id": "f71b69f0-0fca-4222-a354-c487e82f721c", "type": "mosaic", "content": {"title": "Island Life", "body": "Where every view is yours alone.", "images": [{"url": "https://images.unsplash.com/photo-1573843981267-be1999ff37cd?w=800&q=80", "alt": "Aerial view"}, {"url": "https://images.unsplash.com/photo-1540541338287-41700207dee6?w=800&q=80", "alt": "Villa at sunset"}, {"url": "https://images.unsplash.com/photo-1544551763-46a013bb70d5?w=800&q=80", "alt": "Pool deck"}, {"url": "https://images.unsplash.com/photo-1514282401047-d79a71a590e8?w=800&q=80", "alt": "Ocean views"}]}, "layout": {}}, {"id": "8ab8254c-76e4-438d-96e6-2365c7a1be71", "type": "weddings", "content": {"eyebrow": "Weddings", "headline": "An Island to Yourselves", "body": "The entire island can be privately chartered for ceremonies of up to 100 guests. Exchange vows on a sandbank as the sun sets behind the horizon, or beneath the stars on your villa terrace. The dedicated wedding team has one responsibility: to ensure nothing feels anything but effortless.", "image": "https://images.unsplash.com/photo-1519741497674-611481863552?w=1200&q=80"}, "layout": {"variant": "image-right", "accentBg": "#131c14"}}, {"id": "d62694d5-96ec-4310-8b94-203b4e8ecdf4", "type": "quote", "content": {"text": "The moment we arrived, we knew. This was the only place in the world for our wedding.", "attribution": "Sophie & James", "attributionRole": "Married October 2025"}, "layout": {"variant": "centered", "accentBg": "#1a1209"}}, {"id": "8c4c6353-7c88-44bf-9186-e5f48bce2b04", "type": "dining", "content": {"eyebrow": "Dining", "headline": "Chef-Driven, Island-Inspired", "body": "Seven restaurants across the island \u2014 from barefoot beach dining on fresh Maldivian catches to elevated garden-to-table tasting menus. Wedding dinners can be held on private sandbanks, surrounded by lanterns, with a dedicated team handling every element from the first canap\u00e9 to the final toast.", "image": "https://images.unsplash.com/photo-1414235077428-338989a2e8c0?w=1200&q=80"}, "layout": {"variant": "image-left", "accentBg": "#0f0e0c"}}, {"id": "a088dea1-9945-4ab5-bd73-3d53b00f5d10", "type": "wellness", "content": {"eyebrow": "Wellness", "headline": "A Spa Built on Island Healing", "body": "The overwater spa draws on ancient Maldivian healing traditions, blending sea botanicals with modern wellness rituals. Couples can book the entire spa compound for the morning of their wedding \u2014 emerging luminous, unhurried, and completely at ease.", "image": "https://images.unsplash.com/photo-1544161515-4ab6ce6db874?w=1200&q=80"}, "layout": {"variant": "image-right", "accentBg": "#0f0e0c"}}, {"id": "deb6901a-c38e-4875-98c3-962de56a0474", "type": "cta", "content": {"headline": "Begin Your Island Wedding Story", "subline": "Our team is ready to design something extraordinary around you.", "background": "https://images.unsplash.com/photo-1540541338287-41700207dee6?w=1600&q=80", "venueName": "Soneva Jani"}, "layout": {}}]'::jsonb,
